package com.example.documentviewer;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.webkit.WebView;
import android.webkit.WebViewClient;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.io.File;

public class DocumentViewerActivity extends AppCompatActivity {
    private static final String TAG = "DocumentViewerActivity";
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        
        Intent intent = getIntent();
        String action = intent.getAction();
        String type = intent.getType();
        
        if (Intent.ACTION_VIEW.equals(action) && type != null) {
            Uri uri = intent.getData();
            if (uri != null) {
                handleDocument(uri);
            } else {
                Toast.makeText(this, "Invalid file URI", Toast.LENGTH_SHORT).show();
                finish();
            }
        } else {
            Toast.makeText(this, "Unsupported file type", Toast.LENGTH_SHORT).show();
            finish();
        }
    }
    
    private void handleDocument(Uri uri) {
        try {
            String fileExtension = getFileExtension(uri);
            if (isSupportedFileType(fileExtension)) {
                displayDocument(uri);
            } else {
                Toast.makeText(this, "Unsupported file type", Toast.LENGTH_SHORT).show();
                finish();
            }
        } catch (Exception e) {
            Toast.makeText(this, "Error opening file: " + e.getMessage(), Toast.LENGTH_SHORT).show();
            finish();
        }
    }
    
    private void displayDocument(Uri uri) {
        WebView webView = new WebView(this);
        setContentView(webView);
        webView.setWebViewClient(new WebViewClient() {
            @Override
            public boolean shouldOverrideUrlLoading(WebView view, String url) {
                return false;
            }
        });
        
        webView.getSettings().setJavaScriptEnabled(true);
        webView.getSettings().setAllowFileAccess(true);
        
        if (isPdfFile(uri)) {
            webView.loadUrl("file:///android_asset/pdf_viewer.html?file=" + uri.toString());
        } else {
            webView.loadUrl("file://" + uri.getPath());
        }
    }
    
    private String getFileExtension(Uri uri) {
        String filePath = uri.getPath();
        if (filePath != null) {
            int lastDotIndex = filePath.lastIndexOf('.');
            if (lastDotIndex != -1) {
                return filePath.substring(lastDotIndex).toLowerCase();
            }
        }
        return "";
    }
    
    private boolean isSupportedFileType(String extension) {
        return extension.equals(".pdf") || 
               extension.equals(".jpg") || 
               extension.equals(".jpeg") || 
               extension.equals(".png") || 
               extension.equals(".gif") || 
               extension.equals(".bmp");
    }
    
    private boolean isPdfFile(Uri uri) {
        String extension = getFileExtension(uri);
        return extension.equals(".pdf");
    }
}